    handle: "learn-from-home-ugee-s1060w-wireless-skullcandy-method-anc-otterbox-10oz-tumbler-1",
    title: `Learn from Home (UGEE S1060W (Wireless) + Skullcandy Method ANC + Otterbox 10oz Tumbler)`,
    vendor: "UGEE",
    type: "Drawing Tablet",
