export function getProductsByCategory(category: string): Product[] {
  if (category === 'All') return products;
  return products.filter(p => p.category === category);
}

export function getProductsByNavCategory(navCategory: string): Product[] {
  return products.filter(p => p.navCategory === navCategory);
}

export function getProductByHandle(handle: string): Product | undefined {
  return products.find(p => p.handle === handle);
}

export function getProductsByVendor(vendor: string): Product[] {
  return products.filter(p => p.vendor.toLowerCase() === vendor.toLowerCase());
}

export const brands = [...new Set(products.map(p => p.vendor))].sort();
